import{_ as r,o as t,c as n,j as e,a as s,a1 as d}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"兔人","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/6.一次性血统/兔人.md","filePath":"4.资源分区/1.血统与训练/6.一次性血统/兔人.md"}'),o={name:"4.资源分区/1.血统与训练/6.一次性血统/兔人.md"};function l(i,a,p,_,b,c){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"兔人",tabindex:"-1"},[s("兔人 "),e("a",{class:"header-anchor",href:"#兔人","aria-label":'Permalink to "兔人"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌033")])])],-1),d('<h1 id="兔人-1" tabindex="-1">兔人 <a class="header-anchor" href="#兔人-1" aria-label="Permalink to &quot;兔人&quot;">​</a></h1><p>兔人<br> D+600<br> 魔幻本质<br> 一次性血统<br> 概述：兔人起源于妖精荒野，在那里他们说木族语，并且体现了他们自由与旅行的精神。随着时间推移，这些兔人跳到了其他世界中，他们带着精类国度之中的洋溢情感，并且学习了他们需要的新语言。<br> 兔人们两足着地，有着独特的兔子的长脚，并且有着多种颜色的毛皮。他们有着野兔般的敏锐感官，并且充满活力，就像蓬勃的春天。兔人被些许精类气运所祝福，在冒险中，他们时常能够幸运地从危险之中逃脱。<br> 特性：【多样性】【野兔敏锐】【野兔感官】【幸运步伐】【兔子跳】<br> 【多样性】：在购买该血统后你可以重新设定一次自身体积，从体积2或体积5中选择其一，若你选择了体积2，那么你会变成一只小小兔人，获得额外的10米移速；若你选择了体积5，那么你会变成一位兔子兽人，获得额外的2点闪避防御，该特性一经选择无法更改。<br> 【野兔敏锐】：你的反射豁免额外拥有传奇敏捷*2dp内在加值。<br> 【野兔感官】：你现在获得洞察技能数值/2点先攻。你可以在进行感知属性相关检定时将检定中的3dp转化为1附加成功，至多转化洞察技能上的附加成功点。<br> 【幸运步伐】：每轮首次移动时，先投掷一次不附带任何加成的d10自然骰，若这次自然骰出目为10，这次移动的速度提升20+（敏捷属性）*3米。<br> 【兔子跳】：现在，每轮一次，你可以将进行跳跃移动来代替常规移动，可以移动自身基础速度+跳跃成功数米的距离，视为已经符合助跑条件。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',4)])])}const m=r(o,[["render",l]]);export{f as __pageData,m as default};
